fun bad(items: List<String>): String {
    var result = ""
    for (item in items) {
        result += item
    }
    return result
}

fun bad(n: Int): String {
    var s = "prefix:"
    var i = 0
    while (i < n) {
        s += i.toString()
        i++
    }
    return s
}

fun bad(items: List<String>): String {
    var result: String = ""
    for (item in items) {
        result += item
    }
    return result
}

fun bad(n: Int): String {
    var s = ""
    var i = 0
    do {
        s += i.toString()
        i++
    } while (i < n)
    return s
}

fun good(items: List<String>): String {
    val sb = StringBuilder()
    for (item in items) {
        sb.append(item)
    }
    return sb.toString()
}

fun good(items: List<String>): String {
    return items.joinToString("")
}

fun good(items: List<Int>): Int {
    var sum = 0
    for (item in items) {
        sum += item
    }
    return sum
}

fun good(a: String, b: String): String {
    var result = ""
    result += a
    result += b
    return result
}
